-- ============================================================================
-- مواءمة شروحات عائلة N (إذن) مع عناوينها — تكملة تصحيح 2026-07-09
-- ============================================================================
-- قرّر المالك الاحتفاظ بهذه الأكواد. المشكلة المتبقية: شروحاتها كانت موروثة
-- من الشروحات المخلوطة نفسها (N34 «تزوير» كان شرحه عن الإرهاب، N64 «تهديد»
-- شرحه عن السرقة...). هذا الملف يجعل شرح كل كود مطابقاً لعنوانه، بنفس صيغة
-- «الاستئذان المسبق» المعتمدة في الصفوف الحالية. آمن لإعادة التشغيل.
-- ============================================================================

UPDATE public.security_codes SET description = $$إشعار أمني مرتبط بأنشطة تنظيمات غير قانونية يتطلب الاستئذان المسبق من المديرية العامة للأمن قبل دخول الأجنبي إلى تركيا.$$ WHERE code = 'N26';
